module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);

reg [2:0] count;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 3'b000;
        dout_parallel <= 8'b0;
        dout_valid <= 1'b0;
    end
    else begin
        if (din_valid) begin
            dout_parallel <= {din_serial, dout_parallel[7:1]};
            count <= count + 3'b001;
            if (count == 3'b111) begin
                dout_valid <= 1'b1;
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
        else begin
            dout_valid <= 1'b0;
        end
    end
end

endmodule
